import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
const mockClearActiveStudioSession = vi.fn();
const mockReadActiveStudioSession = vi.fn().mockReturnValue(null);
vi.mock("../activeStudioSession.js", () => ({
    clearActiveStudioSession: (...args) => mockClearActiveStudioSession(...args),
    readActiveStudioSession: (...args) => mockReadActiveStudioSession(...args),
}));
const mockCloseStudioWindowsBySession = vi.fn();
vi.mock("../browser.js", () => ({
    closeStudioWindowsBySession: (...args) => mockCloseStudioWindowsBySession(...args),
}));
const mockEmitJson = vi.fn();
vi.mock("../output.js", () => ({
    emitJson: (...args) => mockEmitJson(...args),
}));
const SESSION = "11111111-1111-4111-8111-111111111111";
describe("runClearStudioSession", () => {
    let killMock;
    let savedArgv;
    beforeEach(() => {
        mockClearActiveStudioSession.mockReset().mockReturnValue(true);
        mockReadActiveStudioSession.mockReset().mockReturnValue(null);
        mockCloseStudioWindowsBySession.mockClear();
        mockEmitJson.mockClear();
        killMock = vi
            .spyOn(process, "kill")
            .mockImplementation((() => true));
        savedArgv = process.argv;
        process.argv = ["node", "clearStudioSession.js"];
    });
    afterEach(() => {
        process.argv = savedArgv;
        killMock.mockRestore();
    });
    it("resolves the session from the pointer, reaps the window and poller, then force-clears", async () => {
        mockReadActiveStudioSession.mockReturnValue({
            sessionId: SESSION,
            serviceUrl: "https://test.invalid",
            pollerPid: 123,
            openedAt: "2026-01-01T00:00:00.000Z",
            windowPid: 4242,
        });
        const { runClearStudioSession } = await import("./clearStudioSession.js");
        runClearStudioSession();
        expect(killMock).toHaveBeenCalledWith(4242, "SIGTERM");
        expect(killMock).toHaveBeenCalledWith(123, "SIGTERM");
        expect(mockCloseStudioWindowsBySession).toHaveBeenCalledWith(SESSION);
        expect(mockClearActiveStudioSession).toHaveBeenCalledWith(SESSION, {
            force: true,
        });
        expect(mockEmitJson).toHaveBeenCalledWith({
            event: "cleared",
            sessionId: SESSION,
        });
    });
    it("skips the window close when the record already shows it closed", async () => {
        mockReadActiveStudioSession.mockReturnValue({
            sessionId: SESSION,
            serviceUrl: "https://test.invalid",
            pollerPid: 123,
            openedAt: "2026-01-01T00:00:00.000Z",
            windowPid: 4242,
            windowState: "closed",
        });
        const { runClearStudioSession } = await import("./clearStudioSession.js");
        runClearStudioSession();
        expect(mockCloseStudioWindowsBySession).not.toHaveBeenCalled();
        expect(mockClearActiveStudioSession).toHaveBeenCalledWith(SESSION, {
            force: true,
        });
    });
    it("no-ops with no pointer and no arg", async () => {
        const { runClearStudioSession } = await import("./clearStudioSession.js");
        runClearStudioSession();
        expect(mockEmitJson).toHaveBeenCalledWith({ event: "no-active-studio" });
        expect(killMock).not.toHaveBeenCalled();
        expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
    });
    it("reports not-found and kills nothing when the explicit sessionId does not match the record", async () => {
        process.argv = ["node", "clearStudioSession.js", SESSION];
        mockReadActiveStudioSession.mockReturnValue({
            sessionId: "22222222-2222-4222-8222-222222222222",
            serviceUrl: "https://test.invalid",
            pollerPid: 123,
            openedAt: "2026-01-01T00:00:00.000Z",
            windowPid: 4242,
        });
        mockClearActiveStudioSession.mockReturnValue(false);
        const { runClearStudioSession } = await import("./clearStudioSession.js");
        runClearStudioSession();
        expect(killMock).not.toHaveBeenCalled();
        expect(mockEmitJson).toHaveBeenCalledWith({
            event: "not-found",
            sessionId: SESSION,
        });
    });
    it("never SIGTERMs its own pid (window kill still fires)", async () => {
        mockReadActiveStudioSession.mockReturnValue({
            sessionId: SESSION,
            serviceUrl: "https://test.invalid",
            pollerPid: process.pid,
            openedAt: "2026-01-01T00:00:00.000Z",
            windowPid: 4242,
        });
        const { runClearStudioSession } = await import("./clearStudioSession.js");
        runClearStudioSession();
        expect(killMock).toHaveBeenCalledWith(4242, "SIGTERM");
        expect(killMock).not.toHaveBeenCalledWith(process.pid, "SIGTERM");
        expect(mockEmitJson).toHaveBeenCalledWith({
            event: "cleared",
            sessionId: SESSION,
        });
    });
});
